    47→export function animateRevert(game, row1, col1, row2, col2) {
    48→    game.animating = true;
    49→
    50→    const gem1 = document.querySelector(`[data-row="${row1}"][data-col="${col1}"]`);
    51→    const gem2 = document.querySelector(`[data-row="${row2}"][data-col="${col2}"]`);
    52→
    53→    if (gem1 && gem2) {
    54→        const gem1Rect = gem1.getBoundingClientRect();
    55→        const gem2Rect = gem2.getBoundingClientRect();
    56→
    57→        const deltaX = gem2Rect.left - gem1Rect.left;
    58→        const deltaY = gem2Rect.top - gem1Rect.top;
    59→
    60→        // Apply initial swap animation (fast)
    61→        gem1.style.transform = `translate(${deltaX}px, ${deltaY}px)`;
    62→        gem2.style.transform = `translate(${-deltaX}px, ${-deltaY}px)`;
    63→        gem1.style.transition = "transform 0.20s ease-out";
    64→        gem2.style.transition = "transform 0.20s ease-out";
    65→        gem1.classList.add("invalid-swap");
    66→        gem2.classList.add("invalid-swap");
    67→
    68→        // Revert back to original position (fast)
    69→        setTimeout(() => {
    70→            gem1.style.transform = "translate(0, 0)";
    71→            gem2.style.transform = "translate(0, 0)";
    72→            gem1.style.transition = "transform 0.20s ease-in";
    73→            gem2.style.transition = "transform 0.20s ease-in";
    74→        }, 200);
    75→
    76→        // Clean up after animation
    77→        setTimeout(() => {
    78→            gem1.style.transform = "";
    79→            gem2.style.transform = "";
    80→            gem1.style.transition = "";
    81→            gem2.style.transition = "";
    82→            gem1.classList.remove("invalid-swap");
    83→            gem2.classList.remove("invalid-swap");
    84→            game.animating = false;
    85→        }, 400);
    86→    } else {
    87→        game.animating = false;
    88→    }
    89→}
