    91→export function animateMerges(game, matchGroups, processMergesCallback, speedMultiplier = 1) {
    92→    matchGroups.forEach((group) => {
    93→        const middlePositions = calculateMiddlePositions(game, group.tiles, group);
    94→        const outerTiles = getOuterTiles(group.tiles, middlePositions);
    95→
    96→        // Assign outer tiles to nearest middle positions for better visual flow
    97→        const assignments = assignTilesToTargets(outerTiles, middlePositions);
    98→
    99→        // Animate outer tiles sliding to their assigned middle positions
   100→        assignments.forEach(({ tile, target }) => {
   101→            slideGemTo(tile, target, speedMultiplier);
   102→        });
   103→
   104→        // Mark middle tiles for transformation
   105→        middlePositions.forEach((pos) => {
   106→            const gem = document.querySelector(`[data-row="${pos.row}"][data-col="${pos.col}"]`);
   107→            if (gem) {
   108→                gem.classList.add("merge-target");
   109→            }
   110→        });
   111→    });
   112→
   113→    // Process merges after animation
   114→    setTimeout(() => {
   115→        processMergesCallback(matchGroups);
   116→    }, 400 * speedMultiplier);
   117→}
   118→
   119→function slideGemTo(fromTile, toTile, speedMultiplier = 1) {
   120→    const fromElement = document.querySelector(`[data-row="${fromTile.row}"][data-col="${fromTile.col}"]`);
   121→    const toElement = document.querySelector(`[data-row="${toTile.row}"][data-col="${toTile.col}"]`);
   122→
   123→    if (fromElement && toElement) {
   124→        const fromRect = fromElement.getBoundingClientRect();
   125→        const toRect = toElement.getBoundingClientRect();
   126→
   127→        const deltaX = toRect.left - fromRect.left;
   128→        const deltaY = toRect.top - fromRect.top;
   129→
   130→        fromElement.style.transform = `translate(${deltaX}px, ${deltaY}px)`;
   131→        fromElement.style.transition = `transform ${0.4 * speedMultiplier}s ease-out`;
   132→        fromElement.classList.add("sliding");
   133→
   134→        // Fade out the sliding tile
   135→        setTimeout(() => {
   136→            fromElement.style.opacity = "0";
   137→        }, 300 * speedMultiplier);
   138→    }
   139→}
   140→
   141→function getOuterTiles(allTiles, middleTiles) {
   142→    return allTiles.filter((tile) => !middleTiles.some((middle) => middle.row === tile.row && middle.col === tile.col));
   143→}
   144→
   145→// Assign each outer tile to its nearest target position based on Manhattan distance
   146→function assignTilesToTargets(outerTiles, targetPositions) {
   147→    if (targetPositions.length === 0) return [];
   148→    if (targetPositions.length === 1) {
   149→        // If only one target, all tiles go there
   150→        return outerTiles.map((tile) => ({ tile, target: targetPositions[0] }));
   151→    }
   152→
   153→    // For multiple targets, assign each tile to its nearest target
   154→    // Track how many tiles are assigned to each target for balanced distribution
   155→    const targetCounts = new Map();
   156→    targetPositions.forEach((pos) => {
   157→        targetCounts.set(`${pos.row},${pos.col}`, 0);
   158→    });
   159→
   160→    const assignments = [];
   161→
   162→    // Sort outer tiles to process them in a consistent order
   163→    const sortedOuterTiles = [...outerTiles].sort((a, b) => {
   164→        if (a.row !== b.row) return a.row - b.row;
   165→        return a.col - b.col;
   166→    });
   167→
   168→    for (const tile of sortedOuterTiles) {
   169→        // Find the nearest target position
   170→        let bestTarget = targetPositions[0];
   171→        let bestDistance = Math.abs(tile.row - bestTarget.row) + Math.abs(tile.col - bestTarget.col);
   172→
   173→        for (const target of targetPositions) {
   174→            const distance = Math.abs(tile.row - target.row) + Math.abs(tile.col - target.col);
   175→            if (distance < bestDistance) {
   176→                bestDistance = distance;
   177→                bestTarget = target;
   178→            }
   179→        }
   180→
   181→        assignments.push({ tile, target: bestTarget });
   182→        const key = `${bestTarget.row},${bestTarget.col}`;
   183→        targetCounts.set(key, targetCounts.get(key) + 1);
   184→    }
   185→
   186→    return assignments;
   187→}
   188→
   189→function calculateMiddlePositions(_game, tiles, group = null) {
   190→    const positions = [];
   191→    const length = tiles.length;
   192→
   193→    // Special handling for T and L formations
   194→    if (group && (group.direction === "T-formation" || group.direction === "L-formation")) {
   195→        // For special formations, the "middle" position is the intersection
   196→        positions.push(group.intersection);
   197→        return positions;
   198→    }
   199→
   200→    // Special handling for block formations
   201→    if (group && group.direction === "block_4_formation") {
   202→        // For block formations, the "middle" positions are the two intersections
   203→        return group.intersections;
   204→    }
   205→
   206→    // Special handling for 5-tile lines (should create 1 tile with 4x value)
   207→    if (group && (group.direction === "line_5_horizontal" || group.direction === "line_5_vertical")) {
   208→        // 5 tiles: middle position only (creates 1 tile with 4x value)
   209→        positions.push(tiles[2]);
   210→        return positions;
   211→    }
   212→
   213→    // Regular match logic
   214→    if (length === 3) {
   215→        // 3 tiles: middle position (creates 1 tile with 2x value)
   216→        positions.push(tiles[1]);
   217→    } else if (length === 4) {
   218→        // 4 tiles: two middle positions (creates 2 tiles with 2x value)
   219→        positions.push(tiles[1]);
   220→        positions.push(tiles[2]);
   221→    } else if (length >= 5) {
   222→        // 5+ tiles: single middle position (creates 1 tile with 4x value)
   223→        positions.push(tiles[Math.floor(length / 2)]);
   224→    }
   225→
   226→    return positions;
   227→}
