   260→export function animateUnblocking(game, blockedTiles, updateBlockedTileGoalsCallback, updateGoalDisplayCallback, speedMultiplier = 1) {
   261→    if (blockedTiles.length === 0) return;
   262→
   263→    // Process each blocked tile for animation
   264→    blockedTiles.forEach((blockedEntry) => {
   265→        const tile = blockedEntry.tile || game.board[blockedEntry.row][blockedEntry.col];
   266→
   267→        if (!tile) return; // Already removed
   268→
   269→        // NEW: Handle individual cell X removal for merge-count tiles
   270→        if (blockedEntry.isMergeCount && !blockedEntry.isFullRemoval) {
   271→            // Remove just the X visual for this specific cell
   272→            const blockedElement = document.querySelector(`[data-rect-id="${tile.rectId}"]`);
   273→            if (blockedElement) {
   274→                const xMarker = blockedElement.querySelector(`[data-cell-key="${blockedEntry.cellKey}"]`);
   275→                if (xMarker) {
   276→                    xMarker.classList.add("cell-x-removing");
   277→                    setTimeout(() => xMarker.remove(), 300 * speedMultiplier);
   278→                }
   279→            }
   280→            // Don't remove tile from board - just cleared one cell
   281→            return;
   282→        }
   283→
   284→        // NEW: Full rectangular block removal (all cells cleared)
   285→        if (blockedEntry.isFullRemoval && isRectangularBlocked(tile)) {
   286→            animateRectangularBlockRemoval(game, tile, speedMultiplier);
   287→            return;
   288→        }
   289→
   290→        // NEW: Handle rectangular blocks (existing types)
   291→        if (isRectangularBlocked(tile)) {
   292→            animateRectangularBlockRemoval(game, tile, speedMultiplier);
   293→            return;
   294→        }
   295→
   296→        // EXISTING: Single-cell blocked tile animation
   297→        const blockedElement = document.querySelector(
   298→            `[data-row="${blockedEntry.row}"][data-col="${blockedEntry.col}"]`
   299→        );
   300→
   301→        if (blockedElement) {
   302→            // Add disappear animation class (reverse bounce - inflate then shrink)
   303→            blockedElement.classList.add("disappear");
   304→        }
   305→
   306→        // Remove from board data after animation completes (350ms)
   307→        setTimeout(() => {
   308→            game.board[blockedEntry.row][blockedEntry.col] = null;
   309→        }, 400 * speedMultiplier);
   310→    });
   311→
   312→    // Update blocked tile clearing goals if any blocked tiles were cleared
   313→    if (blockedTiles.length > 0) {
   314→        // Update after animation completes
   315→        setTimeout(() => {
   316→            updateBlockedTileGoalsCallback();
   317→            updateGoalDisplayCallback(false); // Update display without checking completion
   318→            // Let the natural cascade completion in dropGems handle checkLevelComplete
   319→        }, 400 * speedMultiplier);
   320→    }
   321→}
