   323→export function animateCursedExpiration(game, cursedTilesToRemove, cursedTilesToImplode, dropGemsCallback) {
   324→    // Animate disappearing cursed tiles
   325→    if (cursedTilesToRemove.length > 0) {
   326→        cursedTilesToRemove.forEach((pos) => {
   327→            const gem = document.querySelector(`[data-row="${pos.row}"][data-col="${pos.col}"]`);
   328→            if (gem) {
   329→                gem.classList.add("cursed-disappear");
   330→            }
   331→        });
   332→
   333→        // Remove from board after animation
   334→        setTimeout(() => {
   335→            cursedTilesToRemove.forEach((pos) => {
   336→                game.board[pos.row][pos.col] = null;
   337→            });
   338→            dropGemsCallback();
   339→        }, 400);
   340→    }
   341→
   342→    // Animate imploding cursed tiles (adjacent tiles slide in)
   343→    if (cursedTilesToImplode.length > 0) {
   344→        cursedTilesToImplode.forEach((pos) => {
   345→            const adjacentPositions = [
   346→                { row: pos.row - 1, col: pos.col }, // Up
   347→                { row: pos.row + 1, col: pos.col }, // Down
   348→                { row: pos.row, col: pos.col - 1 }, // Left
   349→                { row: pos.row, col: pos.col + 1 }, // Right
   350→            ];
   351→
   352→            // First, mark adjacent tiles with purple background
   353→            adjacentPositions.forEach((adjPos) => {
   354→                if (
   355→                    adjPos.row >= 0 &&
   356→                    adjPos.row < game.boardHeight &&
   357→                    adjPos.col >= 0 &&
   358→                    adjPos.col < game.boardWidth
   359→                ) {
   360→                    const adjTile = game.board[adjPos.row][adjPos.col];
   361→                    if (adjTile && (adjTile.type === "normal" || adjTile.type === "cursed")) {
   362→                        const adjGem = document.querySelector(`[data-row="${adjPos.row}"][data-col="${adjPos.col}"]`);
   363→                        if (adjGem) {
   364→                            adjGem.classList.add("cursed-sucked");
   365→                        }
   366→                    }
   367→                }
   368→            });
   369→
   370→            // After 100ms delay, animate sliding toward cursed tile
   371→            setTimeout(() => {
   372→                adjacentPositions.forEach((adjPos) => {
   373→                    if (
   374→                        adjPos.row >= 0 &&
   375→                        adjPos.row < game.boardHeight &&
   376→                        adjPos.col >= 0 &&
   377→                        adjPos.col < game.boardWidth
   378→                    ) {
   379→                        const adjTile = game.board[adjPos.row][adjPos.col];
   380→                        if (adjTile && (adjTile.type === "normal" || adjTile.type === "cursed")) {
   381→                            const adjGem = document.querySelector(
   382→                                `[data-row="${adjPos.row}"][data-col="${adjPos.col}"]`
   383→                            );
   384→                            const cursedGem = document.querySelector(`[data-row="${pos.row}"][data-col="${pos.col}"]`);
   385→
   386→                            if (adjGem && cursedGem) {
   387→                                const adjRect = adjGem.getBoundingClientRect();
   388→                                const cursedRect = cursedGem.getBoundingClientRect();
   389→
   390→                                const deltaX = cursedRect.left - adjRect.left;
   391→                                const deltaY = cursedRect.top - adjRect.top;
   392→
   393→                                adjGem.style.transform = `translate(${deltaX}px, ${deltaY}px)`;
   394→                                adjGem.style.transition = "transform 0.4s ease-out, opacity 0.4s ease-out";
   395→                                adjGem.classList.add("sliding");
   396→
   397→                                // Fade out the sliding tile
   398→                                setTimeout(() => {
   399→                                    adjGem.style.opacity = "0";
   400→                                }, 300);
   401→                            }
   402→                        }
   403→                    }
   404→                });
   405→            }, 100);
   406→
   407→            // Mark cursed tile for implosion effect
   408→            const cursedGem = document.querySelector(`[data-row="${pos.row}"][data-col="${pos.col}"]`);
   409→            if (cursedGem) {
   410→                cursedGem.classList.add("cursed-implode");
   411→            }
   412→        });
   413→
   414→        // Remove tiles from board after animation (400ms slide + 100ms delay)
   415→        setTimeout(() => {
   416→            cursedTilesToImplode.forEach((pos) => {
   417→                const adjacentPositions = [
   418→                    { row: pos.row - 1, col: pos.col },
   419→                    { row: pos.row + 1, col: pos.col },
   420→                    { row: pos.row, col: pos.col - 1 },
   421→                    { row: pos.row, col: pos.col + 1 },
   422→                ];
   423→
   424→                adjacentPositions.forEach((adjPos) => {
   425→                    if (
   426→                        adjPos.row >= 0 &&
   427→                        adjPos.row < game.boardHeight &&
   428→                        adjPos.col >= 0 &&
   429→                        adjPos.col < game.boardWidth
   430→                    ) {
   431→                        const adjTile = game.board[adjPos.row][adjPos.col];
   432→                        if (adjTile && (adjTile.type === "normal" || adjTile.type === "cursed")) {
   433→                            game.board[adjPos.row][adjPos.col] = null;
   434→                        }
   435→                    }
   436→                });
   437→
   438→                // Remove the cursed tile itself
   439→                game.board[pos.row][pos.col] = null;
   440→            });
   441→            dropGemsCallback();
   442→        }, 500);
   443→    }
   444→}
