   446→export function dropGems(game) {
   447→    const movedGems = [];
   448→    const newGems = [];
   449→
   450→    // Process each column independently with section-based gravity
   451→    for (let col = 0; col < game.boardWidth; col++) {
   452→        // Step 1: Find all immovable blocked tiles in this column
   453→        const immovableBlockerPositions = [];
   454→        const processedRectangles = new Set(); // Track rectangular blocks we've already processed
   455→
   456→        for (let row = 0; row < game.boardHeight; row++) {
   457→            const tile = game.board[row][col];
   458→
   459→            // Check if this tile should block gravity
   460→            if ((isBlocked(tile) || isBlockedWithLife(tile) || isBlockedWithMergeCount(tile)) && tile.immovable !== false) {
   461→                if (isRectangularBlocked(tile)) {
   462→                    // For rectangular blocks, only process once per rectangle
   463→                    if (!processedRectangles.has(tile.rectId)) {
   464→                        processedRectangles.add(tile.rectId);
   465→                        // Add all rows that this rectangle occupies in this column
   466→                        const { row: anchorRow } = tile.rectAnchor;
   467→                        const { rectHeight } = tile;
   468→                        for (let r = anchorRow; r < anchorRow + rectHeight; r++) {
   469→                            immovableBlockerPositions.push(r);
   470→                        }
   471→                    }
   472→                } else {
   473→                    // Single-cell blocked tile
   474→                    immovableBlockerPositions.push(row);
   475→                }
   476→            }
   477→        }
   478→
   479→        // Step 2: Define sections between immovable blockers
   480→        // Sort positions to ensure correct section boundaries
   481→        immovableBlockerPositions.sort((a, b) => a - b);
   482→
   483→        // Each section is { start: rowIndex, end: rowIndex }
   484→        const sections = [];
   485→        let currentSectionStart = 0;
   486→
   487→        for (const blockerRow of immovableBlockerPositions) {
   488→            if (blockerRow > currentSectionStart) {
   489→                // There's a section from currentSectionStart to blockerRow-1
   490→                sections.push({ start: currentSectionStart, end: blockerRow - 1 });
   491→            }
   492→            currentSectionStart = blockerRow + 1;
   493→        }
   494→
   495→        // Add final section from last blocker to bottom of board
   496→        if (currentSectionStart < game.boardHeight) {
   497→            sections.push({ start: currentSectionStart, end: game.boardHeight - 1 });
   498→        }
   499→
   500→        // Step 3: Process gravity within each section independently
   501→        let totalEmptySpaces = 0;
   502→
   503→        for (let sectionIndex = 0; sectionIndex < sections.length; sectionIndex++) {
   504→            const section = sections[sectionIndex];
   505→            let writePos = section.end; // Start writing from bottom of this section
   506→            let sectionEmptyCount = 0;
   507→
   508→            // Scan this section from bottom to top
   509→            for (let row = section.end; row >= section.start; row--) {
   510→                const tile = game.board[row][col];
   511→
   512→                if (tile === null) {
   513→                    sectionEmptyCount++;
   514→                } else {
   515→                    // This is a movable tile (normal, movable_blocked, cursed, joker, etc.)
   516→                    if (row !== writePos) {
   517→                        // Tile needs to fall within this section
   518→                        movedGems.push({ row: writePos, col, fromRow: row });
   519→                        game.board[writePos][col] = game.board[row][col];
   520→                        game.board[row][col] = null;
   521→                    }
   522→                    writePos--;
   523→                }
   524→            }
   525→
   526→            // Only the topmost section (index 0) receives new tiles
   527→            if (sectionIndex === 0) {
   528→                totalEmptySpaces = sectionEmptyCount;
   529→            }
   530→        }
   531→
   532→        // Step 4: Spawn new tiles ONLY in the topmost section
   533→        for (let i = 0; i < totalEmptySpaces; i++) {
   534→            game.board[i][col] = createTile(getRandomTileValue(game));
   535→            newGems.push({ row: i, col });
   536→        }
   537→    }
   538→
   539→    // Only render board if we have moves/new gems to show
   540→    // This prevents breaking ongoing animations
   541→    if (movedGems.length > 0 || newGems.length > 0) {
   542→        game.renderBoard();
   543→
   544→        // IMMEDIATELY hide new gems before they're visible
   545→        newGems.forEach((gem) => {
   546→            const element = document.querySelector(`[data-row="${gem.row}"][data-col="${gem.col}"]`);
   547→            if (element) {
   548→                element.style.opacity = "0";
   549→            }
   550→        });
   551→
   552→        // Animate only the gems that actually moved - NO DELAY for existing tiles
   553→        // Use CSS transition instead of keyframe animation for smooth drops
   554→        movedGems.forEach((gem) => {
   555→            const element = document.querySelector(`[data-row="${gem.row}"][data-col="${gem.col}"]`);
   556→            if (element) {
   557→                // Calculate how far the gem fell
   558→                const distance = (gem.row - gem.fromRow) * (element.offsetHeight + 3); // 3 is the gap
   559→
   560→                // Start from above and animate down
