   577→            if (element) {
   578→                element.classList.add("new-gem");
   579→                element.style.animationDelay = `${index * 0.03}s`; // Faster: 30ms instead of 50ms
   580→            }
   581→        });
   582→    }
   583→
   584→    // Calculate timeout: base animation (600ms for new-gem) + longest delay
   585→    const longestDelay = newGems.length > 0 ? (newGems.length - 1) * 0.03 * 1000 : 0; // Updated to 30ms
   586→    const totalTimeout = 400 + longestDelay;
