    29→export async function processMatches(game) {
    30→    const matchGroups = game.findMatches();
    31→
    32→    // Capture user swap flag before resetting (needed for processMerges callback)
    33→    const wasUserSwap = game.isUserSwap;
    34→    game.isUserSwap = false;
    35→
    36→    if (matchGroups.length === 0) {
    37→        // No matches found, allow interactions again
    38→        game.animating = false;
    39→        game.updateGoalDisplay(true);
    40→        return;
    41→    }
    42→
    43→    // Calculate score using display values (not internal values)
    44→    let totalScore = 0;
    45→    matchGroups.forEach((group) => {
    46→        const displayValue = getDisplayValue(group.value);
    47→        totalScore += displayValue * group.tiles.length;
    48→    });
    49→
    50→    // Update score
    51→    game.score += totalScore;
    52→    game.saveScore(); // Save score to localStorage
    53→
    54→    // Track score towards score goals
