   561→                                if (tile.cellMergeCounts[cellKey] > 0 && !cellsToDecrement.has(rectCellKey)) {
   562→                                    cellToClear = { row: r, col: c, cellKey: cellKey };
   563→                                    break;
   564→                                }
   565→                            }
   566→                            if (cellToClear) break;
   567→                        }
   568→
   569→                        // If we found a cell to clear, decrement it
   570→                        if (cellToClear) {
   571→                            const rectCellKey = `${tile.rectId}_${cellToClear.cellKey}`;
   572→                            cellsToDecrement.add(rectCellKey);
   573→
   574→                            // Find the closest target position for animation
   575→                            let closestTarget = targetPositions[0];
   576→                            let closestDistance =
   577→                                Math.abs(cellToClear.row - closestTarget.row) +
   578→                                Math.abs(cellToClear.col - closestTarget.col);
   579→
   580→                            targetPositions.forEach((target) => {
   581→                                const distance =
   582→                                    Math.abs(cellToClear.row - target.row) + Math.abs(cellToClear.col - target.col);
   583→                                if (distance < closestDistance) {
   584→                                    closestDistance = distance;
   585→                                    closestTarget = target;
   586→                                }
   587→                            });
   588→
   589→                            // Store for animation purposes
   590→                            blockedTilesToRemove.push({
   591→                                rectId: tile.rectId,
   592→                                cellKey: cellToClear.cellKey,
   593→                                row: cellToClear.row,
   594→                                col: cellToClear.col,
   595→                                targetPos: closestTarget,
   596→                                tile: tile,
   597→                                isMergeCount: true, // Flag for animation
   598→                            });
   599→                        }
   600→                    } else if (isBlocked(tile) || isBlockedMovable(tile)) {
   601→                        // Use rectId for deduplication
   602→                        const key = isRectangularBlocked(tile) ? tile.rectId : `${pos.row}_${pos.col}`;
   603→
   604→                        // Skip if already hit by this match group
   605→                        if (hitInThisGroup.has(key)) {
