   608→                        hitInThisGroup.add(key);
   609→
   610→                        if (!blockedTilesToRemove.some((t) => t.key === key)) {
   611→                            // Find the closest target position for animation
   612→                            let closestTarget = targetPositions[0];
   613→                            let closestDistance =
   614→                                Math.abs(pos.row - closestTarget.row) + Math.abs(pos.col - closestTarget.col);
   615→
   616→                            targetPositions.forEach((target) => {
   617→                                const distance = Math.abs(pos.row - target.row) + Math.abs(pos.col - target.col);
   618→                                if (distance < closestDistance) {
   619→                                    closestDistance = distance;
   620→                                    closestTarget = target;
   621→                                }
   622→                            });
   623→
   624→                            blockedTilesToRemove.push({
   625→                                key: key,
   626→                                row: pos.row,
   627→                                col: pos.col,
   628→                                targetPos: closestTarget,
