   654→    // Decrement merge counts for affected cells
   655→    const processedRects = new Set(); // Track which rectangles we've checked for full removal
   656→    cellsToDecrement.forEach((rectCellKey) => {
   657→        // Parse rectCellKey format: "rect_2_3_2_2_2_3" -> extract cell coordinates
   658→        const parts = rectCellKey.split("_");
   659→        const cellKey = `${parts[parts.length - 2]}_${parts[parts.length - 1]}`;
   660→
   661→        // Find the tile object (any cell in the rectangle will point to it)
   662→        const [row, col] = cellKey.split("_").map(Number);
   663→        const tile = game.board[row][col];
   664→
   665→        if (tile && isBlockedWithMergeCount(tile)) {
   666→            // Decrement the cell's merge count
   667→            tile.cellMergeCounts[cellKey]--;
   668→
   669→            // Check if ALL cells are cleared (all counts === 0) only once per rectangle
   670→            if (!processedRects.has(tile.rectId)) {
   671→                processedRects.add(tile.rectId);
   672→
   673→                const allCleared = Object.values(tile.cellMergeCounts).every((count) => count === 0);
   674→
   675→                if (allCleared) {
   676→                    // Mark entire rectangular block for removal
   677→                    blockedTilesToRemove.push({
   678→                        rectId: tile.rectId,
   679→                        row: tile.rectAnchor.row,
   680→                        col: tile.rectAnchor.col,
   681→                        tile: tile,
   682→                        isFullRemoval: true,
