   684→                }
   685→            }
   686→        }
   687→    });
   688→
   689→    // Animate and remove blocked tiles
   690→    animateUnblocking(
   691→        game,
   692→        blockedTilesToRemove,
   693→        () => game.updateBlockedTileGoals(),
   694→        (check) => game.updateGoalDisplay(check),
   695→        speedMultiplier
   696→    );
   697→}
   698→
   699→function trackGoalProgress(game, newValue, count = 1) {
   700→    // Update goal progress when tiles are created
   701→    game.levelGoals.forEach((goal) => {
   702→        if (goal.tileValue === newValue) {
   703→            goal.created += count;
   704→        }
   705→    });
   706→}
   707→
   708→export function checkAndCreateCursedTile(game, value, position) {
   709→    // Check if this value has a cursed goal
   710→    const cursedGoal = game.levelGoals.find((goal) => goal.goalType === "cursed" && goal.tileValue === value);
   711→
   712→    if (!cursedGoal) {
   713→        return false; // No cursed goal for this value
   714→    }
