   111→    const allValues = getUniqueTileValues(game);
   112→
   113→    // Sort from highest to lowest
   114→    allValues.sort((a, b) => b - a);
   115→
   116→    // Try each value from highest to lowest
   117→    for (const testValue of allValues) {
   118→        // Temporarily set joker to this value
   119→        game.board[jokerRow][jokerCol] = createTile(testValue);
   120→
   121→        // Use existing findMatches to check if this creates a valid match
   122→        const matches = game.findMatches();
   123→
   124→        // Check if any match includes our joker position AND has no other jokers
   125→        const validMatch = matches.find((match) => {
   126→            // Check if this match includes our joker position
   127→            const includesJoker = match.tiles.some((tile) => tile.row === jokerRow && tile.col === jokerCol);
   128→
   129→            if (!includesJoker) return false;
   130→
   131→            // Optional: check if match includes the actively dragged tile (source, not target)
   132→            if (requireSwapConnection && game.lastSwapPosition) {
   133→                const includesSourceTile = match.tiles.some(
   134→                    (tile) => tile.row === game.lastSwapPosition.row && tile.col === game.lastSwapPosition.col,
   135→                );
   136→
   137→                if (!includesSourceTile) return false;
   138→            }
   139→
   140→            // Check that no other jokers are in this match
   141→            const hasOtherJokers = match.tiles.some((tile) => {
   142→                // Skip the joker we're testing
   143→                if (tile.row === jokerRow && tile.col === jokerCol) return false;
   144→                // Check if this tile is a joker
   145→                return isJoker(game.board[tile.row][tile.col]);
   146→            });
   147→
   148→            return !hasOtherJokers;
   149→        });
   150→
   151→        if (validMatch) {
   152→            // Found a valid match! Restore the original joker and return the value
   153→            game.board[jokerRow][jokerCol] = originalTile;
   154→            return testValue;
   155→        }
   156→    }
   157→
   158→    // No valid matches found, restore original joker tile
   159→    game.board[jokerRow][jokerCol] = originalTile;
   160→    return null;
   161→}
