   217→function updateDrag(game, x, y) {
   218→    if (!game.isDragging || !game.selectedGem) return;
   219→
   220→    const element = document.elementFromPoint(x, y);
   221→    if (element && element.classList.contains("gem")) {
   222→        // If user drags back to the original tile, cancel the preview
   223→        if (element === game.selectedGem.element) {
   224→            clearDragPreviews();
   225→            return;
   226→        }
   227→
   228→        const targetRow = parseInt(element.dataset.row);
   229→        const targetCol = parseInt(element.dataset.col);
   230→
   231→        // Check if gems are adjacent or allowed by extended free swap rules
   232→        if (canPreviewSwap(game, game.selectedGem.row, game.selectedGem.col, targetRow, targetCol)) {
   233→            previewSwap(game, game.selectedGem.row, game.selectedGem.col, targetRow, targetCol);
   234→        }
   235→    }
   236→}
   237→
   238→function endDrag(game) {
   239→    if (!game.isDragging || !game.selectedGem) return;
   240→
   241→    const previewGems = document.querySelectorAll(".gem.preview");
   242→
   243→    if (previewGems.length > 0) {
   244→        // User dragged to swap
   245→        const targetGem = Array.from(previewGems).find((g) => g !== game.selectedGem.element);
   246→        if (targetGem) {
   247→            const targetRow = parseInt(targetGem.dataset.row);
   248→            const targetCol = parseInt(targetGem.dataset.col);
   249→            trySwap(game, game.selectedGem.row, game.selectedGem.col, targetRow, targetCol);
   250→        }
   251→    } else if (isJoker(game.selectedGem.tile) && !game.activePowerUp) {
   252→        // User tapped on joker without dragging - try to activate it
   253→        // Only activate if not in power-up mode
   254→
   255→        // Check if this is a valid tutorial tap
   256→        if (isTutorialActive(game) && isTutorialTapStep(game)) {
   257→            if (isValidTutorialTap(game, game.selectedGem.row, game.selectedGem.col)) {
   258→                activateJokerByTap(game, game.selectedGem.row, game.selectedGem.col, game.selectedGem.element);
   259→                // Note: Tutorial progression is handled in the joker activation callback
   260→            }
   261→        } else if (!isTutorialActive(game)) {
   262→            activateJokerByTap(game, game.selectedGem.row, game.selectedGem.col, game.selectedGem.element);
   263→        }
   264→    } else if (isTileHammerTile(game.selectedGem.tile) && !game.activePowerUp) {
   265→        // User tapped on hammer tile without dragging - activate it
   266→        // Only activate if not in power-up mode
   267→        activateHammerTileByTap(game, game.selectedGem.row, game.selectedGem.col, game.selectedGem.element);
   268→    } else if (isTileHalverTile(game.selectedGem.tile) && !game.activePowerUp) {
   269→        // User tapped on halver tile without dragging - activate it
   270→        // Only activate if not in power-up mode
   271→        activateHalverTileByTap(game, game.selectedGem.row, game.selectedGem.col, game.selectedGem.element);
   272→    }
   273→
   274→    // Clean up
   275→    document.querySelectorAll(".gem").forEach((gem) => {
   276→        gem.classList.remove("dragging", "preview", "merge-preview", "unblock-preview");
   277→    });
   278→
   279→    // Reset hint timer after user interaction completes
   280→    game.resetHintTimer();
   281→
   282→    game.selectedGem = null;
   283→    game.isDragging = false;
   284→    game.dragStartPos = null;
   285→}
   286→
   287→function activateJokerByTap(game, row, col, element) {
   288→    // Activate joker when tapped
   289→    const bestValue = findBestJokerValue(game, row, col);
   290→
   291→    if (bestValue !== null) {
   292→        // Transform and animate
   293→        game.animating = true;
   294→        element.style.transform = "scale(1.2)";
   295→        element.textContent = getDisplayValue(bestValue);
   296→        element.className = `gem tile-${bestValue}`;
   297→
   298→        setTimeout(() => {
   299→            element.style.transform = "scale(1)";
   300→            game.board[row][col] = createTile(bestValue); // Update board
   301→
   302→            // Set lastSwapPosition to the joker position so other jokers connected to this one can activate
   303→            game.lastSwapPosition = { row, col, movedFrom: { row, col } };
   304→
   305→            game.renderBoard(); // Re-render to show the updated tile
   306→
   307→            // Progress tutorial if this was a tap-only tutorial step
   308→            if (isTutorialActive(game) && isTutorialTapStep(game)) {
   309→                advanceTutorialStep(game);
   310→            }
   311→
   312→            setTimeout(() => {
   313→                game.isUserSwap = true; // Treat tap as user action
   314→                game.processMatches();
   315→            }, 200);
   316→        }, 300);
   317→    } else {
   318→        // No valid match found - indicate to user with a shake animation
   319→        element.style.animation = "shake 0.3s";
   320→        setTimeout(() => {
   321→            element.style.animation = "";
   322→        }, 300);
   323→    }
   324→}
   325→
   326→function activateHammerTileByTap(game, row, col, element) {
   327→    // Activate hammer tile when tapped - removes the tile
   328→
   329→    // Animate removal
   330→    game.animating = true;
   331→    element.style.transform = "scale(0.5)";
   332→    element.style.opacity = "0";
   333→
   334→    setTimeout(() => {
   335→        // Remove the tile from the board
   336→        game.board[row][col] = null;
   337→        game.renderBoard();
   338→
   339→        setTimeout(() => {
   340→            // Drop tiles and process matches
   341→            game.isUserSwap = true;
   342→            game.dropGems();
   343→        }, 200);
   344→    }, 300);
   345→}
   346→
   347→function activateHalverTileByTap(game, row, col, element) {
   348→    // Activate halver tile when tapped - halves the tile's value
   349→    const currentValue = getTileValue(game.board[row][col]);
   350→
   351→    // Can only halve if value is greater than 1
   352→    if (currentValue <= 1) {
   353→        // Cannot halve further - show shake animation
   354→        element.style.animation = "shake 0.3s";
   355→        setTimeout(() => {
   356→            element.style.animation = "";
   357→        }, 300);
   358→        return;
   359→    }
   360→
   361→    // Calculate new value (halve it)
   362→    const newValue = currentValue - 1; // Internal value decreased by 1 (which halves the display value)
   363→
   364→    // Animate the change
   365→    game.animating = true;
   366→    element.style.transform = "scale(1.2)";
   367→
   368→    setTimeout(() => {
   369→        element.style.transform = "scale(1)";
   370→        // Update the tile to regular tile with new value (no longer a halver tile)
   371→        game.board[row][col] = createTile(newValue);
   372→        game.renderBoard();
   373→
   374→        setTimeout(() => {
   375→            // Process any matches that may have been created
   376→            game.isUserSwap = true;
   377→            game.processMatches();
   378→        }, 200);
   379→    }, 300);
   380→}
   381→
   382→function areAdjacent(row1, col1, row2, col2) {
   383→    const rowDiff = Math.abs(row1 - row2);
   384→    const colDiff = Math.abs(col1 - col2);
   385→    return (rowDiff === 1 && colDiff === 0) || (rowDiff === 0 && colDiff === 1);
   386→}
   387→
   388→function clearDragPreviews() {
   389→    document.querySelectorAll(".gem.preview").forEach((gem) => {
   390→        gem.classList.remove("preview");
   391→    });
   392→    document.querySelectorAll(".gem.merge-preview").forEach((gem) => {
   393→        gem.classList.remove("merge-preview");
   394→    });
   395→    document.querySelectorAll(".gem.unblock-preview").forEach((gem) => {
   396→        gem.classList.remove("unblock-preview");
   397→    });
   398→}
   399→
   400→function canPreviewSwap(game, row1, col1, row2, col2) {
   401→    if (areAdjacent(row1, col1, row2, col2)) {
   402→        return true;
   403→    }
   404→
   405→    if (game.activePowerUp === "swap" || game.activePowerUp === "teleport") {
   406→        return true;
   407→    }
   408→
   409→    if (isTeleportSwapAllowed(game, row1, col1, row2, col2)) {
   410→        return true;
   411→    }
   412→
   413→    return isExtendedFreeSwapAllowed(game, row1, col1, row2, col2);
   414→}
   415→
   416→function isTeleportSwapAllowed(game, row1, col1, row2, col2) {
   417→    const tile1 = game.board[row1][col1];
   418→    const tile2 = game.board[row2][col2];
   419→
   420→    // Can't teleport to/from blocked tiles
   421→    if (isBlocked(tile1) || isBlocked(tile2) || isBlockedWithLife(tile1) || isBlockedWithLife(tile2)) {
   422→        return false;
   423→    }
   424→
   425→    const isTeleport1 = (isTileTeleportTile(tile1) || isWildTeleportTile(tile1)) && !tile1.hasBeenSwapped;
   426→
   427→    return isTeleport1;
   428→}
   429→
   430→function isExtendedFreeSwapAllowed(game, row1, col1, row2, col2) {
   431→    if (game.allowNonMatchingSwaps !== true) {
   432→        return false;
   433→    }
   434→
   435→    const isHorizontalSwap = row1 === row2;
   436→    const isVerticalSwap = col1 === col2;
   437→
   438→    if (!isHorizontalSwap && !isVerticalSwap) {
   439→        return false;
   440→    }
   441→
   442→    const tile1 = game.board[row1][col1];
   443→    const tile2 = game.board[row2][col2];
   444→
   445→    const isFreeSwap1 = (isTileFreeSwapTile(tile1) || isTileStickyFreeSwapTile(tile1)) && !tile1.hasBeenSwapped;
   446→    const isFreeSwap2 = (isTileFreeSwapTile(tile2) || isTileStickyFreeSwapTile(tile2)) && !tile2.hasBeenSwapped;
   447→
   448→    const isDirectionalFreeSwap1 =
   449→        !tile1.hasBeenSwapped &&
   450→        ((isTileFreeSwapHorizontalTile(tile1) && isHorizontalSwap) ||
   451→            (isTileFreeSwapVerticalTile(tile1) && isVerticalSwap));
   452→    const isDirectionalFreeSwap2 =
   453→        !tile2.hasBeenSwapped &&
   454→        ((isTileFreeSwapHorizontalTile(tile2) && isHorizontalSwap) ||
   455→            (isTileFreeSwapVerticalTile(tile2) && isVerticalSwap));
   456→
   457→    return isFreeSwap1 || isFreeSwap2 || isDirectionalFreeSwap1 || isDirectionalFreeSwap2;
   458→}
   459→
   460→function previewSwap(game, row1, col1, row2, col2) {
   461→    // Clear previous previews
   462→    clearDragPreviews();
   463→
   464→    // Add preview to both gems
   465→    const gem1 = document.querySelector(`[data-row="${row1}"][data-col="${col1}"]`);
   466→    const gem2 = document.querySelector(`[data-row="${row2}"][data-col="${col2}"]`);
   467→
   468→    if (gem1 && gem2) {
   469→        gem1.classList.add("preview");
   470→        gem2.classList.add("preview");
   471→
   472→        // Get tiles that would merge if swap completes
   473→        const matchTiles = getMatchTilesForSwap(game, row1, col1, row2, col2);
   474→
   475→        // Highlight merge tiles
   476→        for (const tile of matchTiles) {
   477→            const matchGem = document.querySelector(`[data-row="${tile.row}"][data-col="${tile.col}"]`);
   478→            matchGem?.classList.add("merge-preview");
   479→        }
   480→
   481→        // Highlight blocked tiles that would be unblocked
   482→        // matchTiles are in PRE-SWAP coords, convert to POST-SWAP for adjacency check
   483→        const blockedToUnblock = getBlockedTilesForMatch(game, matchTiles, row1, col1, row2, col2);
   484→        for (const pos of blockedToUnblock) {
   485→            const blockedGem = document.querySelector(`[data-row="${pos.row}"][data-col="${pos.col}"]`);
   486→            blockedGem?.classList.add("unblock-preview");
   487→        }
   488→    }
   489→}
   490→
   491→function getBlockedTilesForMatch(game, matchTiles, row1, col1, row2, col2) {
   492→    const blockedSet = new Set();
   493→    const result = [];
   494→
   495→    for (const tile of matchTiles) {
   496→        // Convert pre-swap to post-swap coordinates
   497→        let checkRow = tile.row;
   498→        let checkCol = tile.col;
   499→        if (tile.row === row1 && tile.col === col1) {
   500→            checkRow = row2;
   501→            checkCol = col2;
   502→        } else if (tile.row === row2 && tile.col === col2) {
   503→            checkRow = row1;
   504→            checkCol = col1;
   505→        }
   506→
   507→        const adjacentPositions = [
   508→            { row: checkRow - 1, col: checkCol },
   509→            { row: checkRow + 1, col: checkCol },
   510→            { row: checkRow, col: checkCol - 1 },
   511→            { row: checkRow, col: checkCol + 1 },
   512→        ];
   513→
   514→        for (const pos of adjacentPositions) {
   515→            if (pos.row >= 0 && pos.row < game.boardHeight && pos.col >= 0 && pos.col < game.boardWidth) {
   516→                const key = `${pos.row}_${pos.col}`;
   517→                if (!blockedSet.has(key)) {
   518→                    const adjacentTile = game.board[pos.row][pos.col];
   519→                    if (
   520→                        isBlocked(adjacentTile) ||
   521→                        isBlockedWithLife(adjacentTile) ||
   522→                        isBlockedMovable(adjacentTile) ||
   523→                        isBlockedWithMergeCount(adjacentTile)
   524→                    ) {
   525→                        blockedSet.add(key);
   526→                        result.push(pos);
   527→                    }
   528→                }
   529→            }
   530→        }
   531→    }
   532→
   533→    return result;
   534→}
   535→
   536→export function trySwap(game, row1, col1, row2, col2) {
   537→    if (!game.gameActive) return;
   538→
   539→    // Tutorial validation - only allow defined swaps during tutorial
   540→    if (isTutorialActive(game)) {
   541→        if (!isValidTutorialSwap(game, row1, col1, row2, col2)) {
   542→            game.animateRevert(row1, col1, row2, col2);
   543→            return false;
   544→        }
   545→    }
   546→
   547→    // Prevent swapping if either tile is blocked or blocked with life
   548→    // BLOCKED_MOVABLE tiles CAN be swapped
   549→    if (
   550→        isBlocked(game.board[row1][col1]) ||
   551→        isBlocked(game.board[row2][col2]) ||
   552→        isBlockedWithLife(game.board[row1][col1]) ||
   553→        isBlockedWithLife(game.board[row2][col2])
   554→    ) {
   555→        return;
   556→    }
   557→
   558→    const isAdjacentSwap = areAdjacent(row1, col1, row2, col2);
   559→    const allowExtendedFreeSwap = !isAdjacentSwap && isExtendedFreeSwapAllowed(game, row1, col1, row2, col2);
   560→    const allowTeleportSwap = !isAdjacentSwap && isTeleportSwapAllowed(game, row1, col1, row2, col2);
   561→    const isPowerUpSwap = !isAdjacentSwap && (game.activePowerUp === "swap" || game.activePowerUp === "teleport");
   562→
   563→    if (!isAdjacentSwap && !allowExtendedFreeSwap && !allowTeleportSwap && !isPowerUpSwap) {
   564→        return false;
   565→    }
   566→
   567→    // If animating, queue the swap to execute after animation completes
   568→    if (game.animating) {
   569→        game.interruptCascade = true;
   570→        // Store tile references to validate they haven't changed when executing
   571→        game.pendingSwap = {
   572→            row1,
   573→            col1,
   574→            row2,
   575→            col2,
   576→            tile1: game.board[row1][col1],
   577→            tile2: game.board[row2][col2],
   578→        };
   579→
   580→        // Visualize the pending swap with preview class
   581→        const gem1 = document.querySelector(`[data-row="${row1}"][data-col="${col1}"]`);
   582→        const gem2 = document.querySelector(`[data-row="${row2}"][data-col="${col2}"]`);
   583→        if (gem1) gem1.classList.add("pending-preview");
   584→        if (gem2) gem2.classList.add("pending-preview");
   585→
   586→        return;
   587→    }
   588→
   589→    // Check if either tile is a free swap tile (or sticky free swap) that hasn't been used
   590→    const tile1 = game.board[row1][col1];
   591→    const tile2 = game.board[row2][col2];
   592→
   593→    // Determine if this swap is horizontal or vertical
   594→    const isHorizontalSwap = row1 === row2; // Same row means horizontal swap
   595→    const isVerticalSwap = col1 === col2; // Same column means vertical swap
   596→
   597→    // Check for regular free swap tiles
   598→    const isFreeSwap1 = (isTileFreeSwapTile(tile1) || isTileStickyFreeSwapTile(tile1)) && !tile1.hasBeenSwapped;
   599→    const isFreeSwap2 = (isTileFreeSwapTile(tile2) || isTileStickyFreeSwapTile(tile2)) && !tile2.hasBeenSwapped;
   600→
   601→    // Check for directional free swap tiles and validate direction
   602→    const isDirectionalFreeSwap1 =
   603→        !tile1.hasBeenSwapped &&
   604→        ((isTileFreeSwapHorizontalTile(tile1) && isHorizontalSwap) ||
   605→            (isTileFreeSwapVerticalTile(tile1) && isVerticalSwap));
   606→    const isDirectionalFreeSwap2 =
   607→        !tile2.hasBeenSwapped &&
   608→        ((isTileFreeSwapHorizontalTile(tile2) && isHorizontalSwap) ||
   609→            (isTileFreeSwapVerticalTile(tile2) && isVerticalSwap));
   610→
   611→    const hasFreeSwap = isFreeSwap1 || isFreeSwap2 || isDirectionalFreeSwap1 || isDirectionalFreeSwap2;
   612→
   613→    // Check for teleport tile (only the dragged tile, not the target)
   614→    const hasTeleport = (isTileTeleportTile(tile1) || isWildTeleportTile(tile1)) && !tile1.hasBeenSwapped;
   615→
   616→    // Temporarily swap gems
   617→    const temp = game.board[row1][col1];
   618→    game.board[row1][col1] = game.board[row2][col2];
   619→    game.board[row2][col2] = temp;
   620→
   621→    // Track which tile was moved (the one that changed position)
   622→    game.lastSwapPosition = { row: row2, col: col2, movedFrom: { row: row1, col: col1 } };
   623→
   624→    // Mark this as a user swap for match detection
   625→    game.isUserSwap = true;
   626→
   627→    // Check if this creates any matches (or if using swap power-up or free swap tile)
   628→    const isSwapPowerUp = game.activePowerUp === "swap";
   629→    const isTeleportPowerUp = game.activePowerUp === "teleport";
   630→    const hasMatch = game.hasMatchesForSwap(row1, col1, row2, col2);
   631→    const allowNonMatchingSwap = game.allowNonMatchingSwaps === true;
   632→
   633→    if (hasMatch || isSwapPowerUp || isTeleportPowerUp || hasFreeSwap || hasTeleport || allowNonMatchingSwap) {
   634→        if (!isSwapPowerUp && !isTeleportPowerUp && !hasFreeSwap && !hasTeleport) {
   635→            game.movesUsed++;
   636→            game.updateMovesDisplay();
   637→        }
   638→
   639→        // Flag that we should decrement cursed timers after this turn completes
   640→        game.shouldDecrementCursedTimers = true;
   641→
   642→        // Reset cursed tile creation flag for frequency:0 goals
   643→        game.cursedTileCreatedThisTurn = {};
   644→
   645→        // Mark free swap tile as used
   646→        if (hasFreeSwap) {
   647→            if (isFreeSwap1 || isDirectionalFreeSwap1) {
   648→                game.board[row2][col2].hasBeenSwapped = true;
   649→            }
   650→            if (isFreeSwap2 || isDirectionalFreeSwap2) {
   651→                game.board[row1][col1].hasBeenSwapped = true;
   652→            }
   653→        }
   654→
   655→        // Mark teleport tile as used (tile1 has been swapped to row2/col2)
   656→        if (hasTeleport) {
   657→            game.board[row2][col2].hasBeenSwapped = true;
   658→        }
   659→
   660→        game.animateSwap(row1, col1, row2, col2, () => {
   661→            game.renderBoard();
   662→
   663→            // Progress tutorial if active
   664→            if (isTutorialActive(game)) {
   665→                advanceTutorialStep(game);
   666→            }
   667→
   668→            if (isSwapPowerUp) {
   669→                // Consume power-up
   670→                game.consumePowerUp("swap");
   671→                game.updatePowerUpButtons();
   672→
   673→                // Track power-up usage
   674→                track("power_up_used", {
   675→                    level: game.currentLevel,
   676→                    power_up_type: "swap",
   677→                    remaining_moves: game.maxMoves - game.movesUsed,
   678→                    uses_remaining: game.getTotalPowerUpCount("swap"),
   679→                });
   680→
   681→                game.deactivatePowerUp();
   682→            }
   683→
   684→            if (isTeleportPowerUp) {
   685→                game.consumePowerUp("teleport");
   686→                game.updatePowerUpButtons();
   687→
   688→                track("power_up_used", {
   689→                    level: game.currentLevel,
   690→                    power_up_type: "teleport",
   691→                    remaining_moves: game.maxMoves - game.movesUsed,
   692→                    uses_remaining: game.getTotalPowerUpCount("teleport"),
   693→                });
   694→
   695→                game.deactivatePowerUp();
   696→            }
   697→
   698→            if (!hasMatch && (allowNonMatchingSwap || hasTeleport || isTeleportPowerUp) && !isSwapPowerUp && !hasFreeSwap) {
   699→                game.lastSwapPosition = null;
   700→                game.isUserSwap = false;
   701→            }
   702→
   703→            // Ensure any drag/preview state is cleared so the board can accept new input
   704→            document.querySelectorAll(".gem").forEach((gem) => {
   705→                gem.classList.remove("dragging", "preview", "merge-preview", "unblock-preview");
   706→            });
   707→            game.selectedGem = null;
   708→            game.isDragging = false;
   709→            game.dragStartPos = null;
   710→
   711→            game.processMatches();
   712→        });
   713→
   714→        return true;
   715→    } else {
   716→        // Revert the swap
   717→        game.board[row2][col2] = game.board[row1][col1];
   718→        game.board[row1][col1] = temp;
   719→        game.lastSwapPosition = null;
   720→        game.isUserSwap = false;
   721→        game.animateRevert(row1, col1, row2, col2);
   722→    }
   723→}
