   343→
   344→    // Calculate position bonus (matches closer to bottom trigger more cascades)
   345→    let totalRow = 0;
   346→    let tileCount = 0;
   347→    for (const match of matches) {
   348→        for (const tile of match.tiles) {
   349→            totalRow += tile.row;
   350→            tileCount++;
   351→        }
   352→    }
   353→    // Average row position (0 = top, boardHeight-1 = bottom)
   354→    // Bonus scales from 0 to ~150 based on position
   355→    const avgRow = tileCount > 0 ? totalRow / tileCount : 0;
   356→    const positionBonus = Math.round((avgRow / (game.boardHeight - 1)) * 150);
   357→
   358→    // Compute composite score
   359→    score += maxFormationScore;
   360→    score += totalTilesCleared * 50;
   361→    score += goalProgress * 100;
   362→
   363→    // Blocked tile scoring
   364→    // If a swap clears blocked tiles, heavily prefer it.
   365→    if (blockedCleared > 0) {
   366→        // Massive bonus that dominates most other factors, scaled by cleared blocked tiles.
   367→        score += 10000 + blockedCleared * 500;
   368→    }
   369→
   370→    score += hasSpecialTile ? 200 : 0;
   371→    score += maxValue * 5;
   372→    score += positionBonus;
   373→
   374→    return score;
   375→}
