// Headless game simulation - no DOM, no animation
// Used by MCTS/RL hint systems to evaluate moves

import { applyGravity } from "./gravity.js";
import { findMatches } from "./match-detector.js";
import { processMerges } from "./merge-processor.js";
import { executeSwap } from "./input-handler.js";
import { getDisplayValue } from "./tile-helpers.js";

/**
 * Deep-clone the board (2D array of tile objects).
 */
function cloneBoard(board) {
    return board.map((row) => row.map((tile) => (tile ? { ...tile } : null)));
}

/**
 * Create a minimal game-like context for headless simulation.
 * Copies only the fields needed by findMatches, processMerges, applyGravity.
 */
function createSimContext(game, board) {
    return {
        board,
        boardWidth: game.boardWidth,
        boardHeight: game.boardHeight,
        tileValues: game.tileValues,
        spawnableTileValues: game.spawnableTileValues,
        specialTileConfig: game.specialTileConfig,
        levelGoals: game.levelGoals.map((g) => ({ ...g })), // shallow copy goals
        allowNonMatchingSwaps: game.allowNonMatchingSwaps,
        activePowerUp: null,
        activatedJokerPositions: null,
        powerUpOnSpecialTileUseEnabled: false, // don't grant power-ups during sim
        isUserSwap: false,
        lastSwapPosition: null,
        movesUsed: game.movesUsed,
        maxMoves: game.maxMoves,
        pendingTileLevelShift: false,
        cursedTileCreatedCount: { ...game.cursedTileCreatedCount },
        cursedTileCreatedThisTurn: {},
        shouldDecrementCursedTimers: false,
        matchStats: { tFormationCount: 0, lFormationCount: 0, blockFormationCount: 0, match5Count: 0, match4Count: 0, match3Count: 0 },

        // No-op stubs for methods called by processMerges/createMergedTiles
        findMatches() { return findMatches(this); },
        hasMatchesForSwap(r1, c1, r2, c2) {
            const { hasMatchesForSwap } = require("./match-detector.js");
            return hasMatchesForSwap(this, r1, c1, r2, c2);
        },
        saveScore() {},
        updateGoalDisplay() {},
        updateMovesDisplay() {},
        renderBoard() {},
        dropGems() {},
        checkAndShiftTileLevels() {},
        checkAndGrantPowerUpReward() {},
        grantRandomPowerUp() {},
        grantFormationPowerUp() {},
    };
}

/**
 * Simulate a single complete move (swap → match → merge → gravity cascade).
 *
 * @param {Match3Game} game - Live game instance (not mutated)
 * @param {{ row1: number, col1: number, row2: number, col2: number }} swap
 * @returns {{
 *   newBoard: Array[][],
 *   scoreDelta: number,
 *   goalProgress: Object,   // { [tileValue]: count } created this move
 *   cascades: number,
 *   valid: boolean
 * }}
 */
export function simulateMove(game, swap) {
    const { row1, col1, row2, col2 } = swap;

    // Clone board state
    const board = cloneBoard(game.board);
    const ctx = createSimContext(game, board);

    // Execute the swap (pure board mutation)
    const swapResult = executeSwapHeadless(ctx, row1, col1, row2, col2);
    if (!swapResult.valid) {
        return { valid: false, newBoard: board, scoreDelta: 0, goalProgress: {}, cascades: 0 };
    }

    let scoreDelta = 0;
    const goalProgress = {};
    let cascades = 0;
    const maxCascades = 20; // Safety limit

    // Cascade loop: find matches → merge → gravity → repeat
    while (cascades < maxCascades) {
        ctx.isUserSwap = cascades === 0; // Only first iteration is "user swap"

        const matchGroups = findMatches(ctx);
        if (matchGroups.length === 0) break;

        // Calculate score
        matchGroups.forEach((group) => {
            const displayValue = getDisplayValue(group.value);
            scoreDelta += displayValue * group.tiles.length;
        });

        // Track goal progress (created goals)
        matchGroups.forEach((group) => {
            ctx.levelGoals.forEach((goal) => {
                if (goal.tileValue === group.value + 1 && goal.goalType === "created") {
                    goalProgress[goal.tileValue] = (goalProgress[goal.tileValue] || 0) + 1;
                }
            });
        });

        // Process merges (mutates ctx.board, no DOM/animation)
        processMergesHeadless(ctx, matchGroups);

        // Apply gravity (mutates ctx.board, no DOM/animation)
        applyGravity(ctx);

        cascades++;
        ctx.isUserSwap = false;
        ctx.lastSwapPosition = null;
    }

    return {
        valid: true,
        newBoard: ctx.board,
        scoreDelta,
        goalProgress,
        cascades,
    };
}

/**
 * Headless version of executeSwap - same logic as input-handler.js but without DOM.
 */
function executeSwapHeadless(ctx, row1, col1, row2, col2) {
    // Perform the board swap
    const temp = ctx.board[row1][col1];
    ctx.board[row1][col1] = ctx.board[row2][col2];
    ctx.board[row2][col2] = temp;

    ctx.lastSwapPosition = { row: row2, col: col2, movedFrom: { row: row1, col: col1 } };
    ctx.isUserSwap = true;

    // Check if this creates matches
    const matches = findMatches(ctx);
    const hasMatch = matches.some((match) =>
        match.tiles.some((tile) =>
            (tile.row === row1 && tile.col === col1) || (tile.row === row2 && tile.col === col2)
        )
    );

    if (!hasMatch) {
        // Revert
        ctx.board[row2][col2] = ctx.board[row1][col1];
        ctx.board[row1][col1] = temp;
        ctx.lastSwapPosition = null;
        ctx.isUserSwap = false;
        return { valid: false };
    }

    return { valid: true, hasMatch };
}

/**
 * Headless version of processMerges - mutates ctx.board without DOM/animation.
 */
function processMergesHeadless(ctx, matchGroups) {
    // Clear matched tiles
    matchGroups.forEach((group) => {
        group.tiles.forEach((tile) => {
            ctx.board[tile.row][tile.col] = null;
        });
    });

    // Create merged tiles using the same logic as processMerges
    matchGroups.forEach((group) => {
        processMerges(ctx, [group], ctx.isUserSwap);
    });
}

